query:
DELETE FROM campaigns WHERE accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
DELETE FROM campaign_templates WHERE accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
DELETE FROM appointments WHERE accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
DELETE ci FROM calendar_integrations ci INNER JOIN calendars cal ON ci.calendarId = cal.id WHERE cal.accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
DELETE cw FROM calendar_watches cw INNER JOIN calendars cal ON cw.calendarId = cal.id WHERE cal.accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');

